# Sanwitch GPS Library for ESP32
import machine
import time

class GPS:
    def __init__(self, tx, rx):
        self.uart = machine.UART(1, baudrate=9600, tx=int(tx), rx=int(rx))
        self.latitude = 0.0
        self.longitude = 0.0

    def update(self):
        if self.uart.any():
            try:
                line = self.uart.readline().decode('utf-8', 'ignore')
                if line.startswith('$GPRMC') or line.startswith('$GPGGA'):
                    parts = line.split(',')
                    if line.startswith('$GPRMC') and len(parts) > 6 and parts[2] == 'A':
                        self.latitude = self._to_decimal(parts[3], parts[4])
                        self.longitude = self._to_decimal(parts[5], parts[6])
                        return True
                    if line.startswith('$GPGGA') and len(parts) > 6 and int(parts[6]) > 0:
                        self.latitude = self._to_decimal(parts[2], parts[3])
                        self.longitude = self._to_decimal(parts[4], parts[5])
                        return True
            except: pass
        return False

    def _to_decimal(self, value, direction):
        try:
            if not value or '.' not in value: return 0.0
            dot_idx = value.find('.')
            dd = float(value[:dot_idx-2])
            mm = float(value[dot_idx-2:])
            decimal = dd + (mm / 60)
            if direction in ['S', 'W']: decimal = -decimal
            return decimal
        except: return 0.0

    def get_location(self):
        start = time.ticks_ms()
        while time.ticks_diff(time.ticks_ms(), start) < 500:
            if self.update(): break
        return (self.latitude, self.longitude)

_inst = None
def get_location(tx, rx):
    global _inst
    if _inst is None: _inst = GPS(tx, rx)
    return _inst.get_location()
